function upd(){var left=lw.value*ld.value,right=rw*rd;var ang=Math.max(-15,Math.min(15,(right-left)*2));beam.style.transform="rotate("+ang+"deg)";document.getElementById("state").textContent=left===right?"平衡！力矩相等 ("+left+")":"左力矩 "+left+"，右力矩 "+right;}
