var c=document.getElementById("c"),x=c.getContext("2d"),ang=document.getElementById("ang");
function draw(){var a=+ang.value;document.getElementById("a").textContent=a;x.clearRect(0,0,300,180);x.strokeStyle="#94a3b8";x.beginPath();x.moveTo(0,150);x.lineTo(300,150);x.stroke();
var poleX=120,poleH=60;x.strokeStyle="#334155";x.lineWidth=6;x.beginPath();x.moveTo(poleX,150);x.lineTo(poleX,150-poleH);x.stroke();
var shadow=poleH/Math.tan(a*Math.PI/180);x.strokeStyle="#64748b";x.lineWidth=8;x.beginPath();x.moveTo(poleX,150);x.lineTo(poleX+shadow,150);x.stroke();
x.fillStyle="#f59e0b";x.beginPath();x.arc(poleX-90,150-90-poleH+Math.sin(a*Math.PI/180)*0,0,0,7);
x.beginPath();x.arc(poleX- Math.cos(a*Math.PI/180)*120, 150-Math.sin(a*Math.PI/180)*120,14,0,7);x.fill();}
ang.addEventListener("input",draw);draw();

var tasks=["觀看影片","完成閱讀","做筆記","小測驗","討論"],KEY="demo-progress",done={};
