var pane=document.getElementById("pane"),hint=document.getElementById("hint"),y0=null;
function refresh(){hint.textContent="更新中…";setTimeout(function(){document.getElementById("time").textContent="更新於 "+new Date().toLocaleTimeString();hint.textContent="下拉此區放開以更新";},600);}
pane.addEventListener("pointerdown",function(e){y0=e.clientY;});
pane.addEventListener("pointermove",function(e){if(y0!=null&&e.clientY-y0>60){hint.textContent="放開以更新 ↓";}});
pane.addEventListener("pointerup",function(e){if(y0!=null&&e.clientY-y0>60)refresh();y0=null;});

var ball=document.getElementById("ball"),info=document.getElementById("info");
function handle(e){var x=85+(e.gamma||0)*2,y=85+(e.beta||0)*2;ball.style.left=Math.max(0,Math.min(170,x))+"px";ball.style.top=Math.max(0,Math.min(170,y))+"px";info.textContent="傾斜 β:"+Math.round(e.beta||0)+" γ:"+Math.round(e.gamma||0);}
document.getElementById("enable").onclick=function(){if(typeof DeviceOrientationEvent!=="undefined"&&DeviceOrientationEvent.requestPermission){DeviceOrientationEvent.requestPermission().then(function(s){if(s==="granted")addEventListener("deviceorientation",handle);}).catch(function(){info.textContent="無法取得感測權限";});}else if("DeviceOrientationEvent" in window){addEventListener("deviceorientation",handle);info.textContent="已啟用（請傾斜裝置）";}else{info.textContent="此裝置不支援方向感測";}};

var info=document.getElementById("info");
