var KEY="demo-todo",items=[];try{items=JSON.parse(localStorage.getItem(KEY))||[];}catch(e){}
var list=document.getElementById("list");
function save(){try{localStorage.setItem(KEY,JSON.stringify(items));}catch(e){}}
function draw(){list.innerHTML="";items.forEach(function(it,i){var li=document.createElement("li");li.className=it.done?"done":"";li.innerHTML="<span>"+it.t+"</span><span><button data-a=t data-i="+i+">✓</button> <button data-a=d data-i="+i+">✕</button></span>";list.appendChild(li);});}
document.getElementById("add").onclick=function(){var v=document.getElementById("in").value.trim();if(v){items.push({t:v,done:false});document.getElementById("in").value="";save();draw();}};
list.addEventListener("click",function(e){var b=e.target.closest("button");if(!b)return;var i=+b.dataset.i;if(b.dataset.a==="t")items[i].done=!items[i].done;else items.splice(i,1);save();draw();});draw();

