var c=document.getElementById("rope"),x=c.getContext("2d"),N=14,pts=[];for(var i=0;i<N;i++)pts.push({x:60+i*16,y:20,px:60+i*16,py:20});var drag=false;
c.addEventListener("pointerdown",function(){drag=true;});c.addEventListener("pointerup",function(){drag=false;});
c.addEventListener("pointermove",function(e){if(drag){var b=c.getBoundingClientRect();pts[N-1].x=e.clientX-b.left;pts[N-1].y=e.clientY-b.top;}});
function loop(){for(var i=1;i<N;i++){var p=pts[i];if(i===N-1&&drag)continue;var vx=(p.x-p.px)*0.98,vy=(p.y-p.py)*0.98;p.px=p.x;p.py=p.y;p.x+=vx;p.y+=vy+0.5;}for(var k=0;k<5;k++)for(var i=0;i<N-1;i++){var a=pts[i],b=pts[i+1],dx=b.x-a.x,dy=b.y-a.y,d=Math.hypot(dx,dy)||1,diff=(d-16)/d;if(i>0){a.x+=dx*0.5*diff;a.y+=dy*0.5*diff;}b.x-=dx*0.5*diff;b.y-=dy*0.5*diff;}pts[0].x=60;pts[0].y=20;x.clearRect(0,0,320,220);x.strokeStyle="#0ea5a4";x.lineWidth=3;x.beginPath();pts.forEach(function(p,i){i?x.lineTo(p.x,p.y):x.moveTo(p.x,p.y);});x.stroke();requestAnimationFrame(loop);}loop();
